<section class="eco-card"><h1>Onboarding</h1></section>
<div class="eco-grid"><?php foreach (['pending','running','completed','failed','canceled'] as $k): ?><div class="eco-stat-card"><strong><?= e(strtoupper($k)) ?></strong><div><?= e((string)($stats[$k] ?? 0)) ?></div></div><?php endforeach; ?></div>
<section class="eco-card"><table class="eco-table"><thead><tr><th>ID</th><th>Flow</th><th>User</th><th>Status</th><th>Started</th><th>Completed</th><th>Failed</th><th>Created</th></tr></thead><tbody><?php foreach ($runs as $run): ?><tr><td><a href="/onboarding/runs/<?= e((string)$run['id']) ?>"><?= e((string)$run['id']) ?></a></td><td><?= e((string)($run['flow_name'] ?? $run['flow_key'] ?? '')) ?></td><td><?= e((string)($run['user_display_name'] ?? $run['user_email'] ?? '-')) ?></td><td><span class="eco-badge"><?= e((string)$run['status']) ?></span></td><td><?= e((string)($run['started_at'] ?? '')) ?></td><td><?= e((string)($run['completed_at'] ?? '')) ?></td><td><?= e((string)($run['failed_at'] ?? '')) ?></td><td><?= e((string)($run['created_at'] ?? '')) ?></td></tr><?php endforeach; ?></tbody></table></section>
